import type { LibraryItem } from '@/lib/types';

/** Prefix for school-generated library barcodes (not retail UPC). */
export const LIBRARY_BARCODE_PREFIX = 'LIB';

/** Normalize barcode / UPC for storage and Firestore lookup (student scan uppercases input). */
export function normalizeLibraryUpc(raw: string): string {
  return raw.trim().toUpperCase();
}

export function libraryBarcodeForPrint(item: Pick<LibraryItem, 'upc'>): string {
  return normalizeLibraryUpc(item.upc);
}

/** True when code was generated by this app (LIB + 8 hex chars). */
export function isSchoolLibraryBarcode(raw: string): boolean {
  const code = normalizeLibraryUpc(raw);
  return /^LIB[0-9A-F]{8}$/.test(code);
}

/** Generate a unique school library barcode. */
export function generateLibraryBarcode(): string {
  const bytes = new Uint8Array(4);
  if (typeof crypto !== 'undefined' && crypto.getRandomValues) {
    crypto.getRandomValues(bytes);
  } else {
    for (let i = 0; i < 4; i++) bytes[i] = Math.floor(Math.random() * 256);
  }
  const hex = Array.from(bytes)
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('')
    .toUpperCase();
  return `${LIBRARY_BARCODE_PREFIX}${hex}`;
}

export type LibraryLabelFormat = 'sticker' | 'spine' | 'pocket';
